        function canManageTrade(t) { return STATE.profile.role === 'admin' || (t && t.deptId === STATE.profile.deptId); }
        const DEFAULT_COMPANY = { name: 'SLENO CO., LTD.', website: 'www.sleno.co.kr', address: '1306~7, M-Cluster, 17, Deog-an-ro 104beon-gil, Gwangmyeong-si, Gyeonggi-do, 14353 Republic of Korea', tel: '+82-2-6335-0416', fax: '+82-2-6335-0422', email: 'felix.park@sleno.co.kr', logo: 'data:image/png;base64,' };
        function company() { return STATE.company || DEFAULT_COMPANY; }
